var countHousePlacements = function(n) {
    const MOD = 1000000007n;
    let a = 1n, b = 2n;
    for (let i = 0; i < n - 1; i++) {
        const next = (a + b) % MOD;
        a = b;
        b = next;
    }
    return Number((b * b) % MOD);
};
